  ensures LeftmostEmpty(rooms) == i
  decreases i
{
  if i == 0 {
  } else {
    LeftmostEmptyIs(rooms[1..], i - 1);
  }
}

lemma LeftmostEmptyNone(rooms: seq<int>)
  requires forall j :: 0 <= j < |rooms| ==> rooms[j] != 0
  ensures LeftmostEmpty(rooms) == -1
  decreases |rooms|
{
  if |rooms| == 0 {
  } else {
