    assert Gcd(b, a) == a;
    var k := b / a;
    assert b == a * k;
    assert k >= 2;
    MulLeMonotone(a, 2, k);
  } else {
    assert 0 < r && r < a;
    assert Gcd(b, a) == Gcd(a, r);
    assert r % a == r;
