//     or preserve the total, so Sum(y) <= Sum(x) is necessary.
// GreedyKeep constructs such a removal witness when one exists.
ghost predicate CanTransform(x: seq<int>, y: seq<int>)
{
  |x| == |y| &&
  AllNonNeg(x) &&
  AllNonNeg(y) &&
  ValidRemoval(x, GreedyKeep(x, Sum(y)), Sum(y))
}

// ---- Helper Lemmas ----

lemma SumAppend(s: seq<int>, v: int)
  ensures Sum(s + [v]) == Sum(s) + v
{
  var t := s + [v];
  assert t[..|t|-1] == s;
}

lemma SumCons(s: seq<int>)
  requires |s| > 0
  ensures Sum(s) == s[0] + Sum(s[1..])
  decreases |s|
{
  if |s| == 1 {
    assert s[1..] == [];
  } else {
    SumCons(s[..|s|-1]);
    assert s[..|s|-1][0] == s[0];
    assert s[..|s|-1][1..] == s[1..|s|-1];
    assert s[1..][..|(s[1..])|-1] == s[1..|s|-1];
    assert s[1..][|(s[1..])|-1] == s[|s|-1];
  }
}

lemma SumNonNeg(s: seq<int>)
  requires AllNonNeg(s)
  ensures Sum(s) >= 0
  decreases |s|
{
  if |s| > 0 {
    SumNonNeg(s[..|s|-1]);
  }
}

lemma GreedyKeepLength(x: seq<int>, r: int)
  ensures |GreedyKeep(x, r)| == |x|
  decreases |x|
{
  if |x| > 0 {
    var keep := if r <= 0 then 0 else if r >= x[0] then x[0] else r;
    GreedyKeepLength(x[1..], r - keep);
  }
}

lemma GreedyKeepValid(x: seq<int>, r: int)
  requires AllNonNeg(x)
  requires 0 <= r <= Sum(x)
  ensures |GreedyKeep(x, r)| == |x|
  ensures forall i | 0 <= i < |x| :: 0 <= GreedyKeep(x, r)[i] <= x[i]
  ensures Sum(GreedyKeep(x, r)) == r
  decreases |x|
{
  GreedyKeepLength(x, r);
  if |x| == 0 {
  } else {
    var keep := if r <= 0 then 0 else if r >= x[0] then x[0] else r;
    var gk := GreedyKeep(x, r);
    assert gk == [keep] + GreedyKeep(x[1..], r - keep);

    SumCons(x);
    assert AllNonNeg(x[1..]) by {
      forall j | 0 <= j < |x[1..]|
        ensures x[1..][j] >= 0
      {
        assert x[1..][j] == x[j+1];
      }
    }
    SumNonNeg(x[1..]);

    assert 0 <= r - keep <= Sum(x[1..]);

    GreedyKeepValid(x[1..], r - keep);

    var tail := GreedyKeep(x[1..], r - keep);

    assert |gk| > 0;
    SumCons(gk);
    assert gk[0] == keep;
    assert gk[1..] == tail;

    forall i | 0 <= i < |x|
      ensures 0 <= gk[i] <= x[i]
    {
      if i == 0 {
        assert gk[0] == keep;
        assert 0 <= keep <= x[0];
      } else {
        assert gk[i] == tail[i-1];
        assert x[i] == x[1..][i-1];
      }
    }
  }
}

lemma GreedyKeepSumBound(x: seq<int>, r: int)
  requires AllNonNeg(x)
  requires r >= 0
  ensures Sum(GreedyKeep(x, r)) <= Sum(x)
  ensures Sum(GreedyKeep(x, r)) <= r
  decreases |x|
{
  GreedyKeepLength(x, r);
  if |x| == 0 {
  } else {
    var keep := if r <= 0 then 0 else if r >= x[0] then x[0] else r;
    var gk := GreedyKeep(x, r);
    assert gk == [keep] + GreedyKeep(x[1..], r - keep);

    SumCons(x);
    assert AllNonNeg(x[1..]) by {
      forall j | 0 <= j < |x[1..]|
        ensures x[1..][j] >= 0
      {
        assert x[1..][j] == x[j+1];
      }
    }

    assert r - keep >= 0;
    GreedyKeepSumBound(x[1..], r - keep);

    var tail := GreedyKeep(x[1..], r - keep);
    assert |gk| > 0;
    SumCons(gk);
    assert gk[0] == keep;
    assert gk[1..] == tail;
    assert keep <= x[0];
  }
}

lemma CanTransformIffSumLeq(x: seq<int>, y: seq<int>)
  requires |x| == |y|
  requires AllNonNeg(x)
  requires AllNonNeg(y)
  ensures CanTransform(x, y) <==> Sum(y) <= Sum(x)
{
  SumNonNeg(y);
  if Sum(y) <= Sum(x) {
    GreedyKeepValid(x, Sum(y));
  } else {
    GreedyKeepSumBound(x, Sum(y));
  }
}

method PilesWithStones(x: seq<int>, y: seq<int>) returns (result: bool)
  requires |x| == |y|
  requires AllNonNeg(x)
  requires AllNonNeg(y)
  ensures result == CanTransform(x, y)
{
  var xSum := 0;
  var i := 0;
  while i < |x|
    invariant 0 <= i <= |x|
    invariant xSum == Sum(x[..i])
  {
    assert x[..i+1] == x[..i] + [x[i]];
    SumAppend(x[..i], x[i]);
    xSum := xSum + x[i];
    i := i + 1;
  }
  assert x[..|x|] == x;

  var ySum := 0;
  i := 0;
  while i < |y|
    invariant 0 <= i <= |y|
    invariant ySum == Sum(y[..i])
  {
    assert y[..i+1] == y[..i] + [y[i]];
    SumAppend(y[..i], y[i]);
    ySum := ySum + y[i];
    i := i + 1;
  }


  CanTransformIffSumLeq(x, y);
  result := ySum <= xSum;
}

ghost predicate Beautiful(ny: int, nb: int, nr: int)
{
  nb == ny + 1 && nr == nb + 1
}

ghost predicate ValidChoice(y: int, b: int, r: int, ny: int, nb: int, nr: int)
{
  0 <= ny <= y && 0 <= nb <= b && 0 <= nr <= r && Beautiful(ny, nb, nr)
}

method MaxOrnaments(y: int, b: int, r: int) returns (total: int)
  requires y >= 1 && b >= 2 && r >= 3
  ensures exists ny | 0 <= ny <= y ::
            ValidChoice(y, b, r, ny, ny + 1, ny + 2) &&
            total == ny + (ny + 1) + (ny + 2)
  ensures forall ny | 0 <= ny <= y ::
            ValidChoice(y, b, r, ny, ny + 1, ny + 2) ==>
              ny + (ny + 1) + (ny + 2) <= total
{
  var m := y;
  if b - 1 < m { m := b - 1; }
  if r - 2 < m { m := r - 2; }
  total := 3 * m + 3;

  // Prove the existential: m is a valid choice


  // Prove optimality: for any valid ny, ny <= m so 3*ny+3 <= 3*m+3
  forall ny | 0 <= ny <= y
    ensures ValidChoice(y, b, r, ny, ny + 1, ny + 2) ==>
              ny + (ny + 1) + (ny + 2) <= total
  {
    if ValidChoice(y, b, r, ny, ny + 1, ny + 2) {
      assert ny <= y;
      assert ny + 1 <= b;
      assert ny + 2 <= r;
      assert ny <= m;
    }
  }
}

